            sifir: ["Versioning = simpan SEMUA versi; delete = letak delete marker je, boleh undo", "Versioning kena ENABLE dulu BEFORE replication вҖ” CRR wajib versioning ON kat source & destination", "CRR = Cross-Region (region lain) ; SRR = Same-Region Replication (region sama, beza account/bucket)", "Replication = ASYNC + objek BARU sahaja (existing object kena S3 Batch Replication)", "MFA Delete = extra protection, kena MFA untuk delete version (lawan accidental/malicious delete)"],
            perangkap: [{"soalan": "Developer accidentally overwrite file penting dalam S3. Macam mana recover ke versi sebelum?", "umpan": "Enable CRR вҖ” orang ingat 'replication = backup', tapi CRR cuma copy ke region lain, tak bagi balik versi LAMA dalam bucket asal.", "betul": "S3 Versioning вҖ” keyword 'restore previous version / undo overwrite' = Versioning (setiap overwrite jadi version baru)."}, {"soalan": "Compliance kata objects mesti disimpan di region kedua untuk DR. Pilih apa?", "umpan": "S3 Versioning sahaja вҖ” versioning lindung dari delete tapi semua versi DUDUK region sama; region down = tetap hilang.", "betul": "Cross-Region Replication (CRR) вҖ” keyword 'different region / DR / data residency' = CRR (ingat: versioning kena ON dulu)."}],
