            perangkap: [{"soalan": "Partner luar hantar file harian guna SFTP, company nak file terus masuk S3 tanpa manage server. Pilih apa?", "umpan": "Launch EC2 + install OpenSSH SFTP server вҖ” boleh, tapi kena patch, scale, jaga HA sendiri = banyak ops overhead.", "betul": "AWS Transfer Family вҖ” keyword 'managed SFTP / partner file exchange / land in S3 / no code change' = Transfer Family."}, {"soalan": "Nak terima file dari partner via SFTP secara ONGOING. DataSync ke?", "umpan": "AWS DataSync вҖ” DataSync ada kaitan 'transfer file', tapi ia untuk migration berjadual ke AWS, bukan endpoint SFTP untuk partner upload.", "betul": "AWS Transfer Family вҖ” keyword 'SFTP/FTP endpoint untuk users/partners' = Transfer Family, BUKAN DataSync."}],
