            perangkap: [{"soalan": "HPC workload perlu node-to-node latency paling rendah + throughput paling tinggi. Placement group mana?", "umpan": "Spread placement group вҖ” 'spread' bunyi macam bagus untuk performance, tapi spread = sebar untuk availability, bukan low latency.", "betul": "Cluster placement group вҖ” keyword 'lowest latency / highest throughput / HPC / tightly-coupled' = Cluster (1 AZ)."}, {"soalan": "Batch job boleh interrupt, nak jimat kos maksimum, tak kisah kalau instance kena ambil balik. Pilih apa?", "umpan": "Reserved Instance вҖ” jimat tapi kena commit 1-3 tahun; untuk workload sementara/interruptible ia bukan paling murah.", "betul": "Spot Instances вҖ” keyword 'fault-tolerant / interruptible / cheapest / flexible timing' = Spot (sampai 90% off, 2-min notice)."}],
