            perangkap: [{"soalan": "HPC workload perlu jutaan IOPS untuk scratch/shuffle space, data sementara boleh dibina semula kalau hilang. Pilih?", "umpan": "EBS io2 вҖ” sebab 'IOPS tinggi' terus terfikir io2 Provisioned IOPS.", "betul": "Instance Store вҖ” keyword 'jutaan IOPS + scratch + data boleh hilang'. io2 max 64K IOPS & melalui network; Instance Store fizikal = jutaan IOPS, percuma, sesuai untuk scratch."}, {"soalan": "Database storage MESTI survive walaupun instance stop atau host fail. Pilih?", "umpan": "Instance Store вҖ” sebab 'laju' nampak bagus untuk database.", "betul": "EBS вҖ” keyword 'survive stop/failure (persistent)'. Instance Store EPHEMERAL: stop/terminate/host fail = data hilang. Database perlu persistent = EBS."}],
