            perangkap: [{"soalan": "Imej X-ray jarang dibuka TAPI bila doktor minta kena dapat dalam milisaat, kos rendah. Class mana?", "umpan": "Glacier Flexible Retrieval вҖ” nampak 'jarang access = Glacier' jadi pilih Flexible.", "betul": "Glacier Instant Retrieval. Flexible kena restore job (minit-jam), tak boleh ms. Keyword: 'millisecond retrieval' + 'rarely access' вҶ’ Instant."}, {"soalan": "Data compliance dalam Deep Archive, audit minta retrieve 'dalam beberapa minit'. Boleh?", "umpan": "Pilih Expedited tier untuk Deep Archive вҖ” anggap semua Glacier ada Expedited.", "betul": "TAK BOLEH. Deep Archive tiada Expedited; paling laju Standard ~12 jam. Kalau perlu segera kena Glacier Flexible/Instant. Keyword: 'Deep Archive' + 'minutes' = trap."}],
