            perangkap: [{"soalan": "App microservices (API Gateway вҶ’ Lambda вҶ’ DynamoDB) jadi lambat tapi team tak tahu komponen mana punca latency. Service untuk identify bottleneck?", "umpan": "CloudWatch вҖ” sebab dia kumpul metrics latency tiap service, nampak boleh diagnose.", "betul": "AWS X-Ray вҖ” keyword 'distributed tracing / mana bottleneck merentas microservices' = X-Ray service map. CloudWatch bagi angka per-service, tapi tak jahit jadi satu trace end-to-end."}, {"soalan": "Message kadang tak sampai destinasi dalam sistem SQS + Lambda + API Gateway. Nak debug aliran message. Service?", "umpan": "CloudTrail вҖ” sebab nak audit apa jadi, nampak macam jejak aktiviti.", "betul": "X-Ray вҖ” keyword 'trace message path / mana message hilang dalam distributed system' = X-Ray. CloudTrail jejak API call, bukan aliran message dalam app."}],
